#!/usr/bin/env bash
# AstroPrecise — one-file desktop installer.
# Run this on YOUR computer:   bash add-to-desktop.sh
#
# It adds an AstroPrecise icon to your desktop and app menu that opens
# the live site (https://jonnydavx-eng.github.io/astroprecise/) in its
# own app-style window. No repo or server needed. Linux only;
# on macOS/Windows just install the site as a PWA from Chrome instead.

set -euo pipefail

URL="https://jonnydavx-eng.github.io/astroprecise/"
ICON_DIR="$HOME/.local/share/icons/hicolor/512x512/apps"
BIN_DIR="$HOME/.local/bin"
APP_DIR="$HOME/.local/share/applications"

mkdir -p "$ICON_DIR" "$BIN_DIR" "$APP_DIR"

# ── the icon, embedded so this file is all you need ──
base64 -d > "$ICON_DIR/astroprecise.png" <<'ICON_EOF'

ICON_EOF

# ── tiny launcher: app window if Chrome/Chromium exists, else default browser ──
cat > "$BIN_DIR/astroprecise" <<'LAUNCH_EOF'
#!/usr/bin/env bash
URL="https://jonnydavx-eng.github.io/astroprecise/"
for b in google-chrome google-chrome-stable chromium chromium-browser brave-browser microsoft-edge; do
  if command -v "$b" >/dev/null 2>&1; then exec "$b" --app="$URL"; fi
done
exec xdg-open "$URL"
LAUNCH_EOF
chmod +x "$BIN_DIR/astroprecise"

# ── desktop entry ──
DESKTOP_ENTRY="[Desktop Entry]
Type=Application
Name=AstroPrecise
Comment=Birth charts, horoscopes, and The Instrument
Exec=$BIN_DIR/astroprecise
Icon=$ICON_DIR/astroprecise.png
Terminal=false
Categories=Utility;Education;
Keywords=astrology;birth chart;horoscope;zodiac;"

echo "$DESKTOP_ENTRY" > "$APP_DIR/astroprecise.desktop"
chmod +x "$APP_DIR/astroprecise.desktop"
echo "✦ App menu entry installed"

if [ -d "$HOME/Desktop" ]; then
  echo "$DESKTOP_ENTRY" > "$HOME/Desktop/AstroPrecise.desktop"
  chmod +x "$HOME/Desktop/AstroPrecise.desktop"
  command -v gio >/dev/null 2>&1 && gio set "$HOME/Desktop/AstroPrecise.desktop" metadata::trusted true 2>/dev/null || true
  echo "✦ Desktop icon installed"
fi

command -v update-desktop-database >/dev/null 2>&1 && update-desktop-database "$APP_DIR" 2>/dev/null || true
command -v gtk-update-icon-cache >/dev/null 2>&1 && gtk-update-icon-cache -q "$HOME/.local/share/icons/hicolor" 2>/dev/null || true

echo ""
echo "Done. Look for ✦ AstroPrecise on your desktop and in your app menu."
